CREATE TABLE dim_warehouse (
        warehouse_code INTEGER PRIMARY KEY,
        warehouse_name TEXT,
        latitude REAL,
        longitude REAL
    );
CREATE TABLE dim_customer (
        customer_code INTEGER PRIMARY KEY,
        customer_name TEXT,
        sales_class_code TEXT,
        sales_class_name TEXT,
        customer_group_code TEXT,
        customer_group_name TEXT,
        latitude REAL,
        longitude REAL
    );
CREATE TABLE dim_salesman (
        salesman_code INTEGER PRIMARY KEY,
        salesman_name TEXT
    );
CREATE TABLE dim_item (
        item_code TEXT PRIMARY KEY,
        item_name TEXT,
        category_code TEXT,
        category_name TEXT
    );
CREATE TABLE dim_route (
        route_code INTEGER PRIMARY KEY
    );
CREATE TABLE fact_customer_visits (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        visit_date TEXT,
        user_code INTEGER,
        route_code INTEGER,
        warehouse_code INTEGER,
        customer_code INTEGER,
        arrival_time TEXT,
        out_time TEXT,
        total_time_mins INTEGER,
        visit_latitude REAL,
        visit_longitude REAL,
        FOREIGN KEY (route_code) REFERENCES dim_route(route_code),
        FOREIGN KEY (warehouse_code) REFERENCES dim_warehouse(warehouse_code),
        FOREIGN KEY (customer_code) REFERENCES dim_customer(customer_code)
    );
CREATE TABLE sqlite_sequence(name,seq);
CREATE TABLE fact_journey_plans (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        journey_date TEXT,
        route_code INTEGER,
        warehouse_code INTEGER,
        customer_code INTEGER,
        visit_sequence INTEGER,
        FOREIGN KEY (route_code) REFERENCES dim_route(route_code),
        FOREIGN KEY (warehouse_code) REFERENCES dim_warehouse(warehouse_code),
        FOREIGN KEY (customer_code) REFERENCES dim_customer(customer_code)
    );
CREATE TABLE fact_sales (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        trx_code INTEGER,
        trx_date TEXT,
        item_type TEXT,
        route_code INTEGER,
        warehouse_code INTEGER,
        customer_code INTEGER,
        trx_type TEXT,
        item_code TEXT,
        quantity_pcs REAL,
        unit_price REAL,
        total_discount_amount REAL,
        total_tax_amount REAL,
        promotion_id INTEGER,
        return_item_invoice_ref TEXT,
        salesman_code INTEGER,
        FOREIGN KEY (route_code) REFERENCES dim_route(route_code),
        FOREIGN KEY (warehouse_code) REFERENCES dim_warehouse(warehouse_code),
        FOREIGN KEY (customer_code) REFERENCES dim_customer(customer_code),
        FOREIGN KEY (item_code) REFERENCES dim_item(item_code),
        FOREIGN KEY (salesman_code) REFERENCES dim_salesman(salesman_code)
    );
CREATE INDEX idx_cv_date ON fact_customer_visits(visit_date);
CREATE INDEX idx_cv_route ON fact_customer_visits(route_code);
CREATE INDEX idx_cv_customer ON fact_customer_visits(customer_code);
CREATE INDEX idx_cv_warehouse ON fact_customer_visits(warehouse_code);
CREATE INDEX idx_cv_date_route ON fact_customer_visits(visit_date, route_code);
CREATE INDEX idx_jp_date ON fact_journey_plans(journey_date);
CREATE INDEX idx_jp_route ON fact_journey_plans(route_code);
CREATE INDEX idx_jp_customer ON fact_journey_plans(customer_code);
CREATE INDEX idx_jp_date_route ON fact_journey_plans(journey_date, route_code);
CREATE INDEX idx_sales_date ON fact_sales(trx_date);
CREATE INDEX idx_sales_route ON fact_sales(route_code);
CREATE INDEX idx_sales_customer ON fact_sales(customer_code);
CREATE INDEX idx_sales_item ON fact_sales(item_code);
CREATE INDEX idx_sales_salesman ON fact_sales(salesman_code);
CREATE INDEX idx_sales_warehouse ON fact_sales(warehouse_code);
CREATE INDEX idx_sales_trxtype ON fact_sales(trx_type);
CREATE INDEX idx_sales_date_route ON fact_sales(trx_date, route_code);
CREATE INDEX idx_sales_date_customer ON fact_sales(trx_date, customer_code);
CREATE INDEX idx_sales_trxcode ON fact_sales(trx_code);

