import { useEffect, useState } from 'react';
import { useAppStore } from '../../store/store';
import api from '../../api/client';
import { ChevronDown, Calendar } from 'lucide-react';

const personas = [
  { id: 'emp-06', name: 'Amit Singh', role: 'Sales Representative', roleId: 'role-sr' },
  { id: 'emp-08', name: 'Ravi Joshi', role: 'Sales Representative', roleId: 'role-sr' },
  { id: 'emp-09', name: 'Lakshmi Iyer', role: 'Sales Representative', roleId: 'role-sr' },
  { id: 'emp-05', name: 'Suresh Kumar', role: 'Sales Supervisor', roleId: 'role-ss' },
  { id: 'emp-04', name: 'Anita Desai', role: 'Area Sales Manager', roleId: 'role-asm' },
  { id: 'emp-02', name: 'Priya Sharma', role: 'Regional Sales Manager', roleId: 'role-rsm' },
  { id: 'emp-01', name: 'Rajesh Mehta', role: 'National Sales Manager', roleId: 'role-nsm' },
  { id: 'emp-12', name: 'Kavita Rao', role: 'Key Account Manager', roleId: 'role-kam' },
];

const periods = [
  { value: '2026-01', label: 'January 2026' },
  { value: '2026-02', label: 'February 2026' },
  { value: '2025-12', label: 'December 2025' },
  { value: '2025-Q4', label: 'Q4 2025' },
  { value: '2026-Q1', label: 'Q1 2026' },
];

export default function Header() {
  const { currentPersona, setPersona, selectedPeriod, setSelectedPeriod } = useAppStore();
  const [personaOpen, setPersonaOpen] = useState(false);

  return (
    <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 flex-shrink-0">
      <div className="flex items-center gap-2 text-sm text-slate-500">
        <span className="font-medium text-slate-900">WINIT SFA</span>
        <span>/</span>
        <span>Commission Management</span>
      </div>

      <div className="flex items-center gap-4">
        {/* Period selector */}
        <div className="flex items-center gap-2">
          <Calendar className="w-4 h-4 text-slate-400" />
          <select
            value={selectedPeriod}
            onChange={(e) => setSelectedPeriod(e.target.value)}
            className="text-sm border border-slate-300 rounded-lg px-3 py-1.5 bg-white focus:outline-none focus:ring-2 focus:ring-primary-500"
          >
            {periods.map((p) => (
              <option key={p.value} value={p.value}>{p.label}</option>
            ))}
          </select>
        </div>

        {/* Persona switcher */}
        <div className="relative">
          <button
            onClick={() => setPersonaOpen(!personaOpen)}
            className="flex items-center gap-3 px-3 py-1.5 rounded-lg border border-slate-300 hover:bg-slate-50 transition-colors"
          >
            <div className="w-8 h-8 rounded-full bg-primary-100 text-primary-700 flex items-center justify-center text-sm font-semibold">
              {currentPersona.name.split(' ').map(n => n[0]).join('')}
            </div>
            <div className="text-left">
              <div className="text-sm font-medium text-slate-900">{currentPersona.name}</div>
              <div className="text-xs text-slate-500">{currentPersona.role}</div>
            </div>
            <ChevronDown className="w-4 h-4 text-slate-400" />
          </button>

          {personaOpen && (
            <>
              <div className="fixed inset-0 z-10" onClick={() => setPersonaOpen(false)} />
              <div className="absolute right-0 top-full mt-1 w-72 bg-white rounded-xl shadow-lg border border-slate-200 py-2 z-20">
                <div className="px-3 py-2 text-xs font-medium text-slate-400 uppercase tracking-wider">
                  Switch Persona
                </div>
                {personas.map((p) => (
                  <button
                    key={p.id}
                    onClick={() => { setPersona(p); setPersonaOpen(false); }}
                    className={`w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 transition-colors ${
                      currentPersona.id === p.id ? 'bg-primary-50' : ''
                    }`}
                  >
                    <div className="w-8 h-8 rounded-full bg-primary-100 text-primary-700 flex items-center justify-center text-xs font-semibold">
                      {p.name.split(' ').map(n => n[0]).join('')}
                    </div>
                    <div className="text-left">
                      <div className="text-sm font-medium text-slate-900">{p.name}</div>
                      <div className="text-xs text-slate-500">{p.role}</div>
                    </div>
                  </button>
                ))}
              </div>
            </>
          )}
        </div>
      </div>
    </header>
  );
}

import { create } from 'zustand';

export const useAppStore = create((set, get) => ({
  // Current persona for role-based views
  currentPersona: {
    id: 'emp-06',
    name: 'Amit Singh',
    role: 'Sales Representative',
    roleId: 'role-sr',
  },
  setPersona: (persona) => set({ currentPersona: persona }),

  // Period selector
  selectedPeriod: '2026-01',
  setSelectedPeriod: (period) => set({ selectedPeriod: period }),

  // Sidebar state
  sidebarCollapsed: false,
  toggleSidebar: () => set((s) => ({ sidebarCollapsed: !s.sidebarCollapsed })),

  // Employees list (cached)
  employees: [],
  setEmployees: (employees) => set({ employees }),
}));

