import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs) {
  return twMerge(clsx(inputs));
}

export function formatCurrency(amount) {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount);
}

export function formatPercent(value, decimals = 1) {
  return `${Number(value).toFixed(decimals)}%`;
}

export function formatNumber(num) {
  return new Intl.NumberFormat('en-IN').format(num);
}

export function getStatusColor(status) {
  const colors = {
    draft: 'badge-gray',
    active: 'badge-success',
    expired: 'badge-danger',
    archived: 'badge-gray',
    pending: 'badge-warning',
    submitted: 'badge-info',
    manager_approved: 'badge-info',
    finance_approved: 'badge-info',
    hr_approved: 'badge-success',
    rejected: 'badge-danger',
    locked: 'badge-success',
    running: 'badge-warning',
    completed: 'badge-success',
    failed: 'badge-danger',
  };
  return colors[status] || 'badge-gray';
}

export function getStatusLabel(status) {
  return status?.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()) || '';
}

import { useState, useEffect } from 'react';
import api from '../api/client';
import { useAppStore } from '../store/store';
import { formatCurrency, formatPercent, cn } from '../lib/utils';
import {
  TrendingUp, TrendingDown, DollarSign, Users, Target, BarChart3,
  ArrowUpRight, ArrowDownRight, ShoppingBag, Wallet, Award, AlertTriangle,
  AlertCircle, Calculator
} from 'lucide-react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, LineChart, Line, Legend, RadialBarChart, RadialBar
} from 'recharts';

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#ec4899'];

export default function DashboardPage() {
  const { currentPersona, selectedPeriod } = useAppStore();

  // Determine dashboard type based on role
  const roleLevel = getRoleLevel(currentPersona.roleId);

  if (roleLevel >= 4) return <ExecutiveDashboard period={selectedPeriod} />;
  if (roleLevel >= 2) return <ManagerDashboard employeeId={currentPersona.id} period={selectedPeriod} persona={currentPersona} />;
  return <SalespersonDashboard employeeId={currentPersona.id} period={selectedPeriod} persona={currentPersona} />;
}

function getRoleLevel(roleId) {
  const levels = {
    'role-psr': 1, 'role-sr': 1, 'role-de': 1, 'role-mer': 1,
    'role-ss': 2, 'role-asm': 3, 'role-kam': 3,
    'role-rsm': 4, 'role-zsm': 5, 'role-nsm': 6,
  };
  return levels[roleId] || 1;
}

// ==================== SALESPERSON DASHBOARD ====================
function SalespersonDashboard({ employeeId, period, persona }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get(`/dashboard/salesperson/${employeeId}?period=${period}`)
      .then(setData)
      .catch(() => setData(null))
      .finally(() => setLoading(false));
  }, [employeeId, period]);

  if (loading) return <DashboardSkeleton />;
  if (!data) return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-900">My Dashboard</h1>
        <p className="text-slate-500 mt-1">Welcome back, {persona.name}</p>
      </div>
      <div className="card p-12 text-center">
        <Calculator className="w-12 h-12 text-slate-300 mx-auto mb-3" />
        <h3 className="text-lg font-medium text-slate-700 mb-1">No Commission Data</h3>
        <p className="text-slate-500">Run a calculation for this period to see your dashboard</p>
      </div>
    </div>
  );

  const { sales, payout, kpi_results } = data;
  const collectionPercent = sales.total_sales > 0 ? (sales.total_collections / sales.total_sales * 100) : 0;
  const returnPercent = sales.total_sales > 0 ? (sales.total_returns / sales.total_sales * 100) : 0;

  const kpiChartData = kpi_results.map(k => ({
    name: k.code.replace(/_/g, ' ').slice(0, 12),
    achievement: Math.min(k.achievement_percent, 150),
    target: 100,
  }));

  const payoutBreakdown = payout ? [
    { name: 'Gross', value: payout.gross_payout },
    { name: 'Multiplier', value: payout.multiplier_amount },
    { name: 'Penalty', value: -payout.penalty_amount },
    { name: 'Cap Adj', value: -payout.cap_adjustment },
  ].filter(d => d.value !== 0) : [];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-900">My Dashboard</h1>
        <p className="text-slate-500 mt-1">Welcome back, {persona.name}</p>
      </div>

      {/* Big Payout Number */}
      {payout && (
        <div className="card p-6 bg-gradient-to-r from-primary-600 to-primary-700 text-white">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-primary-200 text-sm font-medium">Estimated Commission Payout</p>
              <p className="text-4xl font-bold mt-1">{formatCurrency(payout.net_payout)}</p>
              <p className="text-primary-200 text-sm mt-2">
                Status: <span className="text-white font-medium">{payout.approval_status?.replace(/_/g, ' ').toUpperCase()}</span>
              </p>
            </div>
            <Wallet className="w-16 h-16 text-primary-300 opacity-50" />
          </div>
        </div>
      )}

      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <MetricCard icon={DollarSign} label="Total Sales" value={formatCurrency(sales.total_sales)} color="emerald" />
        <MetricCard icon={ShoppingBag} label="Units Sold" value={sales.total_units.toLocaleString()} color="blue" />
        <MetricCard icon={Target} label="Collection %" value={formatPercent(collectionPercent)} color="amber" />
        <MetricCard
          icon={AlertTriangle}
          label="Return %"
          value={formatPercent(returnPercent)}
          color={returnPercent > 8 ? 'rose' : 'slate'}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* KPI Achievement Chart */}
        {kpiChartData.length > 0 && (
          <div className="card p-5">
            <h3 className="font-semibold text-slate-900 mb-4">KPI Achievement</h3>
            <ResponsiveContainer width="100%" height={250}>
              <BarChart data={kpiChartData} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
                <XAxis type="number" domain={[0, 150]} tick={{ fontSize: 11 }} tickFormatter={v => `${v}%`} />
                <YAxis type="category" dataKey="name" tick={{ fontSize: 10 }} width={90} />
                <Tooltip formatter={v => `${v.toFixed(1)}%`} />
                <Bar dataKey="achievement" fill="#6366f1" radius={[0,4,4,0]} />
                {/* 100% target line rendered via reference */}
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}

        {/* Payout Breakdown */}
        {payoutBreakdown.length > 0 && (
          <div className="card p-5">
            <h3 className="font-semibold text-slate-900 mb-4">Payout Breakdown</h3>
            <div className="space-y-3">
              {payoutBreakdown.map((item, i) => (
                <div key={item.name} className="flex items-center justify-between py-2 border-b border-slate-100 last:border-0">
                  <span className="text-sm text-slate-600">{item.name}</span>
                  <span className={cn('text-sm font-semibold', item.value >= 0 ? 'text-slate-900' : 'text-rose-600')}>
                    {item.value >= 0 ? '+' : ''}{formatCurrency(item.value)}
                  </span>
                </div>
              ))}
              <div className="flex items-center justify-between pt-2 border-t-2 border-slate-300">
                <span className="text-sm font-bold text-slate-900">Net Payout</span>
                <span className="text-lg font-bold text-primary-600">{formatCurrency(payout.net_payout)}</span>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* KPI Results Table */}
      {kpi_results.length > 0 && (
        <div className="card">
          <div className="p-5 border-b border-slate-200">
            <h3 className="font-semibold text-slate-900">KPI Detail</h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-slate-200 bg-slate-50">
                  <th className="text-left py-3 px-5 font-medium text-slate-600">KPI</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Target</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Actual</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Achievement</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Weight</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Payout</th>
                </tr>
              </thead>
              <tbody>
                {kpi_results.map(k => (
                  <tr key={k.kpi_id || k.code} className="border-b border-slate-100">
                    <td className="py-3 px-5">
                      <div className="font-medium text-slate-900">{k.kpi_name}</div>
                      <div className="text-xs text-slate-400">{k.category}</div>
                    </td>
                    <td className="py-3 px-4 text-right font-mono text-slate-600">
                      {k.unit === 'currency' ? formatCurrency(k.target_value) : k.target_value}
                    </td>
                    <td className="py-3 px-4 text-right font-mono text-slate-900">
                      {k.unit === 'currency' ? formatCurrency(k.actual_value) : Number(k.actual_value).toFixed(1)}
                    </td>
                    <td className="py-3 px-4 text-right">
                      <span className={cn('font-semibold', k.achievement_percent >= 100 ? 'text-emerald-600' : k.achievement_percent >= 70 ? 'text-amber-600' : 'text-rose-600')}>
                        {formatPercent(k.achievement_percent)}
                      </span>
                    </td>
                    <td className="py-3 px-4 text-right text-slate-600">{k.weight}%</td>
                    <td className="py-3 px-4 text-right font-semibold text-slate-900">{formatCurrency(k.weighted_payout)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

// ==================== MANAGER DASHBOARD ====================
function ManagerDashboard({ employeeId, period, persona }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
