  // Helper to generate transactions for an employee
  function genSales(empId, custIds, prodIds, terrId, totalTarget, achievePercent, opts = {}) {
    const { returnPercent = 3, collectionPercent = 90, strategicBias = false } = opts;
    const totalAmount = totalTarget * (achievePercent / 100);
    const txnCount = Math.floor(15 + Math.random() * 20);
    const amtPerTxn = totalAmount / txnCount;

    for (let i = 0; i < txnCount; i++) {
      const custId = custIds[Math.floor(Math.random() * custIds.length)];
      let prodId = prodIds[Math.floor(Math.random() * prodIds.length)];
      // Bias toward strategic products if needed
      if (strategicBias && Math.random() < 0.4) {
        const strategicProds = prodIds.filter(p => ['prod-01', 'prod-03', 'prod-07', 'prod-10', 'prod-13'].includes(p));
        if (strategicProds.length) prodId = strategicProds[Math.floor(Math.random() * strategicProds.length)];
      }
      const prod = products.find(p => p.id === prodId);
      const amount = amtPerTxn * (0.7 + Math.random() * 0.6);
      const qty = Math.max(1, Math.round(amount / (prod?.unit_price || 50)));
      const day = String(Math.floor(1 + Math.random() * 28)).padStart(2, '0');

      txns.push({
        id: uuid(),
        employee_id: empId,
        customer_id: custId,
        product_id: prodId,
        transaction_type: 'sale',
        quantity: qty,
        amount: Math.round(amount * 100) / 100,
        transaction_date: `2026-01-${day}`,
        period,
        territory_id: terrId,
      });
    }

    // Returns
    const returnAmount = totalAmount * (returnPercent / 100);
    const returnCount = Math.max(1, Math.floor(txnCount * 0.1));
    for (let i = 0; i < returnCount; i++) {
      const custId = custIds[Math.floor(Math.random() * custIds.length)];
      const prodId = prodIds[Math.floor(Math.random() * prodIds.length)];
      const prod = products.find(p => p.id === prodId);
      const amt = (returnAmount / returnCount) * (0.8 + Math.random() * 0.4);
      const qty = Math.max(1, Math.round(amt / (prod?.unit_price || 50)));
      const day = String(Math.floor(5 + Math.random() * 23)).padStart(2, '0');

      txns.push({
        id: uuid(),
        employee_id: empId,
        customer_id: custId,
        product_id: prodId,
        transaction_type: 'return',
        quantity: qty,
        amount: Math.round(amt * 100) / 100,
        transaction_date: `2026-01-${day}`,
        period,
        territory_id: terrId,
      });
    }

    // Collections
    const collectionAmount = totalAmount * (collectionPercent / 100);
    const collCount = Math.max(1, Math.floor(txnCount * 0.5));
    for (let i = 0; i < collCount; i++) {
      const custId = custIds[Math.floor(Math.random() * custIds.length)];
      const prodId = prodIds[0]; // Collection linked to primary product
      const amt = (collectionAmount / collCount) * (0.8 + Math.random() * 0.4);
      const day = String(Math.floor(10 + Math.random() * 18)).padStart(2, '0');

      txns.push({
        id: uuid(),
        employee_id: empId,
        customer_id: custId,
        product_id: prodId,
        transaction_type: 'collection',
        quantity: 0,
        amount: Math.round(amt * 100) / 100,
        transaction_date: `2026-01-${day}`,
        period,
        territory_id: terrId,
      });
    }

    // Previous period (for growth calculations) - roughly 80% of current
    const prevAmount = totalAmount * 0.8;
    const prevTxnCount = Math.floor(txnCount * 0.7);
    for (let i = 0; i < prevTxnCount; i++) {
      const custId = custIds[Math.floor(Math.random() * custIds.length)];
      const prodId = prodIds[Math.floor(Math.random() * prodIds.length)];
      const prod = products.find(p => p.id === prodId);
      const amount = (prevAmount / prevTxnCount) * (0.7 + Math.random() * 0.6);
      const qty = Math.max(1, Math.round(amount / (prod?.unit_price || 50)));

      txns.push({
        id: uuid(),
        employee_id: empId,
        customer_id: custId,
        product_id: prodId,
        transaction_type: 'sale',
        quantity: qty,
        amount: Math.round(amount * 100) / 100,
        transaction_date: `2025-01-${String(Math.floor(1 + Math.random() * 28)).padStart(2, '0')}`,
        period: prevPeriod,
        territory_id: terrId,
      });
    }
  }

