  genSales('emp-08', mumbaiCustomers, mumbaiProducts, 'terr-mumbai', 500000, 125, { strategicBias: true, returnPercent: 2, collectionPercent: 95 });

  // emp-09 (Lakshmi, SR Chennai) - 55% achiever (below threshold, tests eligibility)
  genSales('emp-09', chennaiCustomers, chennaiProducts, 'terr-chennai', 500000, 55, { returnPercent: 5, collectionPercent: 55 });

  // emp-10 (Deepak, PSR Delhi) - 100% achiever
  genSales('emp-10', delhiCustomers, delhiProducts, 'terr-delhi', 300000, 100, { returnPercent: 3, collectionPercent: 85 });

  // emp-11 (Manoj, DE Delhi) - 90% achiever
  genSales('emp-11', delhiCustomers, delhiProducts, 'terr-delhi', 200000, 90, { returnPercent: 2, collectionPercent: 92 });

  // emp-12 (Kavita, KAM) - 105% but HIGH returns (tests penalty)
  genSales('emp-12', kaCustomers, [...delhiProducts, ...mumbaiProducts], 'terr-nat', 800000, 105, { returnPercent: 12, collectionPercent: 80 });

  console.log(`Generated ${txns.length} transactions`);
  insert('transactions', txns);

  // ==================== AUDIT TRAIL ====================
  const auditEntries = [
    { id: uuid(), entity_type: 'plan', entity_id: 'plan-01', action: 'created', changes: JSON.stringify({ name: 'Field Sales Monthly Incentive', status: 'draft' }), performed_by: 'emp-01' },
    { id: uuid(), entity_type: 'plan', entity_id: 'plan-01', action: 'activated', changes: JSON.stringify({ status: { from: 'draft', to: 'active' } }), performed_by: 'emp-01' },
    { id: uuid(), entity_type: 'plan', entity_id: 'plan-02', action: 'created', changes: JSON.stringify({ name: 'Supervisor Quarterly Bonus', status: 'draft' }), performed_by: 'emp-01' },
    { id: uuid(), entity_type: 'plan', entity_id: 'plan-02', action: 'activated', changes: JSON.stringify({ status: { from: 'draft', to: 'active' } }), performed_by: 'emp-01' },
  ];
  insert('audit_trail', auditEntries);

  console.log('Seed complete!');
  console.log(`  Roles: ${roles.length}`);
  console.log(`  Territories: ${territories.length}`);
  console.log(`  Products: ${products.length}`);
  console.log(`  Customers: ${customers.length}`);
  console.log(`  Employees: ${employees.length}`);
  console.log(`  KPIs: ${kpis.length}`);
  console.log(`  Plans: ${plans.length}`);
  console.log(`  Transactions: ${txns.length}`);
}

