  batchInsert('commission_plans', [plan1, plan2, plan3]);

  // Plan Roles
  batchInsert('plan_roles', [
    { id: uuid(), plan_id: 'plan-01', role_id: 'role-sr' },
    { id: uuid(), plan_id: 'plan-02', role_id: 'role-ss' },
    { id: uuid(), plan_id: 'plan-02', role_id: 'role-asm' },
