  batchInsert('slab_sets', slabSets);

  const slabTiers = [
    // Revenue Step Slab (plan-01)
    { id: uuid(), slab_set_id: 'slab-01', tier_order: 1, min_percent: 0, max_percent: 70, rate: 0, rate_type: 'percentage' },
