                <YAxis type="category" dataKey="name" tick={{ fontSize: 10 }} width={90} />
                <Tooltip formatter={v => `${v.toFixed(1)}%`} />
                <Bar dataKey="achievement" fill="#6366f1" radius={[0,4,4,0]} />
                {/* 100% target line rendered via reference */}
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}

        {/* Payout Breakdown */}
        {payoutBreakdown.length > 0 && (
          <div className="card p-5">
            <h3 className="font-semibold text-slate-900 mb-4">Payout Breakdown</h3>
            <div className="space-y-3">
              {payoutBreakdown.map((item, i) => (
                <div key={item.name} className="flex items-center justify-between py-2 border-b border-slate-100 last:border-0">
                  <span className="text-sm text-slate-600">{item.name}</span>
                  <span className={cn('text-sm font-semibold', item.value >= 0 ? 'text-slate-900' : 'text-rose-600')}>
                    {item.value >= 0 ? '+' : ''}{formatCurrency(item.value)}
                  </span>
                </div>
              ))}
              <div className="flex items-center justify-between pt-2 border-t-2 border-slate-300">
                <span className="text-sm font-bold text-slate-900">Net Payout</span>
                <span className="text-lg font-bold text-primary-600">{formatCurrency(payout.net_payout)}</span>
