                      <div className="text-xs text-slate-400">{k.category}</div>
                    </td>
                    <td className="py-3 px-4 text-right font-mono text-slate-600">
                      {k.unit === 'currency' ? formatCurrency(k.target_value) : k.target_value}
                    </td>
                    <td className="py-3 px-4 text-right font-mono text-slate-900">
                      {k.unit === 'currency' ? formatCurrency(k.actual_value) : Number(k.actual_value).toFixed(1)}
                    </td>
                    <td className="py-3 px-4 text-right">
                      <span className={cn('font-semibold', k.achievement_percent >= 100 ? 'text-emerald-600' : k.achievement_percent >= 70 ? 'text-amber-600' : 'text-rose-600')}>
