import { useState, useEffect } from 'react';
import api from '../api/client';
import { useAppStore } from '../store/store';
import { formatCurrency, formatPercent, cn } from '../lib/utils';
import {
  TrendingUp, TrendingDown, DollarSign, Users, Target, BarChart3,
  ArrowUpRight, ArrowDownRight, ShoppingBag, Wallet, Award, AlertTriangle,
  AlertCircle, Calculator
} from 'lucide-react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, LineChart, Line, Legend, RadialBarChart, RadialBar
} from 'recharts';

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#ec4899'];

export default function DashboardPage() {
  const { currentPersona, selectedPeriod } = useAppStore();

  // Determine dashboard type based on role
  const roleLevel = getRoleLevel(currentPersona.roleId);

  if (roleLevel >= 4) return <ExecutiveDashboard period={selectedPeriod} />;
  if (roleLevel >= 2) return <ManagerDashboard employeeId={currentPersona.id} period={selectedPeriod} persona={currentPersona} />;
  return <SalespersonDashboard employeeId={currentPersona.id} period={selectedPeriod} persona={currentPersona} />;
}

function getRoleLevel(roleId) {
  const levels = {
    'role-psr': 1, 'role-sr': 1, 'role-de': 1, 'role-mer': 1,
    'role-ss': 2, 'role-asm': 3, 'role-kam': 3,
    'role-rsm': 4, 'role-zsm': 5, 'role-nsm': 6,
  };
  return levels[roleId] || 1;
}

