        <MetricCard icon={ShoppingBag} label="Units Sold" value={sales.total_units.toLocaleString()} color="blue" />
        <MetricCard icon={Target} label="Collection %" value={formatPercent(collectionPercent)} color="amber" />
        <MetricCard
          icon={AlertTriangle}
          label="Return %"
          value={formatPercent(returnPercent)}
