                <YAxis type="category" dataKey="name" tick={{ fontSize: 10 }} width={90} />
                <Tooltip formatter={v => `${v.toFixed(1)}%`} />
                <Bar dataKey="achievement" fill="#6366f1" radius={[0,4,4,0]} />
