              <div className="flex items-center justify-between pt-2 border-t-2 border-slate-300">
                <span className="text-sm font-bold text-slate-900">Net Payout</span>
                <span className="text-lg font-bold text-primary-600">{formatCurrency(payout.net_payout)}</span>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* KPI Results Table */}
      {kpi_results.length > 0 && (
        <div className="card">
          <div className="p-5 border-b border-slate-200">
            <h3 className="font-semibold text-slate-900">KPI Detail</h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-slate-200 bg-slate-50">
                  <th className="text-left py-3 px-5 font-medium text-slate-600">KPI</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Target</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Actual</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Achievement</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Weight</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Payout</th>
                </tr>
              </thead>
              <tbody>
                {kpi_results.map(k => (
                  <tr key={k.kpi_id || k.code} className="border-b border-slate-100">
                    <td className="py-3 px-5">
                      <div className="font-medium text-slate-900">{k.kpi_name}</div>
                      <div className="text-xs text-slate-400">{k.category}</div>
                    </td>
                    <td className="py-3 px-4 text-right font-mono text-slate-600">
                      {k.unit === 'currency' ? formatCurrency(k.target_value) : k.target_value}
                    </td>
                    <td className="py-3 px-4 text-right font-mono text-slate-900">
                      {k.unit === 'currency' ? formatCurrency(k.actual_value) : Number(k.actual_value).toFixed(1)}
                    </td>
                    <td className="py-3 px-4 text-right">
                      <span className={cn('font-semibold', k.achievement_percent >= 100 ? 'text-emerald-600' : k.achievement_percent >= 70 ? 'text-amber-600' : 'text-rose-600')}>
                        {formatPercent(k.achievement_percent)}
                      </span>
                    </td>
                    <td className="py-3 px-4 text-right text-slate-600">{k.weight}%</td>
                    <td className="py-3 px-4 text-right font-semibold text-slate-900">{formatCurrency(k.weighted_payout)}</td>
