                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

// ==================== MANAGER DASHBOARD ====================
function ManagerDashboard({ employeeId, period, persona }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get(`/dashboard/manager/${employeeId}?period=${period}`)
      .then(setData)
      .catch(() => setData(null))
