      {/* ROI Card */}
      <div className="card p-6 bg-gradient-to-r from-emerald-600 to-teal-600 text-white">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-emerald-100 text-sm font-medium">Commission ROI</p>
            <p className="text-3xl font-bold mt-1">
              {data.total_payouts > 0 ? `${(data.total_sales / data.total_payouts).toFixed(1)}x` : 'N/A'}
            </p>
            <p className="text-emerald-200 text-sm mt-1">Sales generated per rupee of commission</p>
          </div>
          <Award className="w-14 h-14 text-emerald-300 opacity-50" />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Sales by Territory */}
        {territoryData.length > 0 && (
          <div className="card p-5">
            <h3 className="font-semibold text-slate-900 mb-4">Sales by Territory</h3>
            <ResponsiveContainer width="100%" height={250}>
              <BarChart data={territoryData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
                <XAxis dataKey="territory" tick={{ fontSize: 11 }} />
                <YAxis tick={{ fontSize: 11 }} tickFormatter={v => `AED ${(v/1000).toFixed(0)}k`} />
                <Tooltip formatter={v => formatCurrency(v)} />
                <Bar dataKey="sales" radius={[4,4,0,0]}>
                  {territoryData.map((entry, i) => (
                    <Cell key={i} fill={entry.fill} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}

        {/* Sales by Category */}
        {categoryData.length > 0 && (
          <div className="card p-5">
            <h3 className="font-semibold text-slate-900 mb-4">Sales by Category</h3>
            <ResponsiveContainer width="100%" height={250}>
              <PieChart>
