          <p className="text-2xl font-bold text-rose-600">{formatCurrency(data.total_returns)}</p>
          <p className="text-xs text-slate-400 mt-1">
            {data.total_sales > 0 ? formatPercent(data.total_returns / data.total_sales * 100) : '0%'} of sales
          </p>
        </div>
        <div className="card p-5">
          <h4 className="text-sm text-slate-500 mb-1">Total Collections</h4>
          <p className="text-2xl font-bold text-emerald-600">{formatCurrency(data.total_collections)}</p>
          <p className="text-xs text-slate-400 mt-1">
            {data.total_sales > 0 ? formatPercent(data.total_collections / data.total_sales * 100) : '0%'} collection rate
          </p>
        </div>
      </div>
    </div>
  );
}

// ==================== SHARED COMPONENTS ====================

function MetricCard({ icon: Icon, label, value, color = 'slate' }) {
  const colorClasses = {
    emerald: 'bg-emerald-50 text-emerald-600',
    blue: 'bg-blue-50 text-blue-600',
    amber: 'bg-amber-50 text-amber-600',
    rose: 'bg-rose-50 text-rose-600',
    primary: 'bg-primary-50 text-primary-600',
    slate: 'bg-slate-50 text-slate-600',
  };

  return (
    <div className="card p-4">
      <div className="flex items-center gap-3">
        <div className={cn('w-10 h-10 rounded-lg flex items-center justify-center', colorClasses[color])}>
          <Icon className="w-5 h-5" />
        </div>
        <div>
          <p className="text-xs text-slate-500">{label}</p>
          <p className="text-lg font-bold text-slate-900">{value}</p>
        </div>
      </div>
    </div>
  );
}

function DashboardSkeleton() {
  return (
    <div className="space-y-6">
      <div className="h-8 w-48 bg-slate-200 rounded animate-pulse" />
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[1,2,3,4].map(i => (
          <div key={i} className="card p-4">
            <div className="h-12 bg-slate-100 rounded animate-pulse" />
          </div>
        ))}
      </div>
      <div className="card p-5 h-80 animate-pulse bg-slate-100" />
    </div>
  );
}

