 17→export function runCalculationPipeline({ plan_id, period, created_by, is_simulation = false, overrides = {} }) {
 18→  const db = getDb();
 19→  const startTime = Date.now();
 20→  
 21→  // Load plan configuration
 22→  const plan = db.prepare('SELECT * FROM commission_plans WHERE id = ?').get(plan_id);
 23→  if (!plan) throw new Error('Plan not found');
 24→  
 25→  // Create calculation run
 26→  const runId = uuid();
 27→  db.prepare(`
 28→    INSERT INTO calculation_runs (id, plan_id, period, status, is_simulation, simulation_params, created_by)
 29→    VALUES (?, ?, ?, 'running', ?, ?, ?)
 30→  `).run(runId, plan_id, period, is_simulation ? 1 : 0, JSON.stringify(overrides), created_by);
 31→  
 32→  const steps = [];
 33→  const log = (stepNum, name, detail) => {
 34→    steps.push({ step: stepNum, name, ...detail, timestamp: Date.now() - startTime });
 35→  };
 36→  
 37→  try {
 38→    // Get eligible employees for this plan
 39→    const planRoles = db.prepare('SELECT role_id FROM plan_roles WHERE plan_id = ?').all(plan_id).map(r => r.role_id);
 40→    const planTerritories = db.prepare('SELECT territory_id FROM plan_territories WHERE plan_id = ?').all(plan_id).map(t => t.territory_id);
 41→    
 42→    const employees = db.prepare(`
 43→      SELECT e.*, r.name as role_name FROM employees e
 44→      JOIN roles r ON e.role_id = r.id
 45→      WHERE e.is_active = 1 AND e.role_id IN (${planRoles.map(() => '?').join(',')})
 46→    `).all(...planRoles);
 47→    
 48→    // Filter by territory if specified
 49→    const filteredEmployees = planTerritories.length > 0
 50→      ? employees.filter(e => planTerritories.includes(e.territory_id))
 51→      : employees;
 52→    
 53→    log(0, 'Initialize', { employee_count: filteredEmployees.length, plan: plan.name });
 54→    
 55→    // Load plan KPIs
 56→    const planKpis = db.prepare(`
 57→      SELECT pk.*, k.name as kpi_name, k.code as kpi_code, k.formula, k.unit, k.direction, k.category as kpi_category
 58→      FROM plan_kpis pk JOIN kpi_definitions k ON pk.kpi_id = k.id
 59→      WHERE pk.plan_id = ?
 60→    `).all(plan_id);
 61→    
 62→    // Load rules
 63→    const ruleSets = db.prepare('SELECT * FROM rule_sets WHERE plan_id = ?').all(plan_id);
 64→    for (const rs of ruleSets) {
 65→      rs.rules = db.prepare('SELECT * FROM rules WHERE rule_set_id = ?').all(rs.id);
 66→    }
 67→    const eligibilityRules = db.prepare('SELECT * FROM eligibility_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 68→    const multiplierRules = db.prepare('SELECT * FROM multiplier_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 69→    const penaltyRules = db.prepare('SELECT * FROM penalty_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 70→    const cappingRules = db.prepare('SELECT * FROM capping_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 71→    const splitRules = db.prepare('SELECT * FROM split_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 72→    for (const sr of splitRules) {
 73→      sr.participants = db.prepare('SELECT * FROM split_participants WHERE split_rule_id = ?').all(sr.id);
 74→    }
 75→    
 76→    // Load slab config
 77→    const slabSets = {};
 78→    for (const pk of planKpis) {
 79→      if (pk.slab_set_id) {
 80→        const ss = db.prepare('SELECT * FROM slab_sets WHERE id = ?').get(pk.slab_set_id);
 81→        if (ss) {
 82→          ss.tiers = db.prepare('SELECT * FROM slab_tiers WHERE slab_set_id = ? ORDER BY tier_order').all(ss.id);
 83→          slabSets[pk.kpi_id] = ss;
 84→        }
 85→      }
 86→    }
 87→    
 88→    const allPayouts = [];
 89→    
 90→    for (const employee of filteredEmployees) {
 91→      const empContext = {
 92→        employee,
 93→        plan,
 94→        period,
 95→        overrides,
 96→        basePayout: overrides.base_payout ?? plan.base_payout,
 97→      };
 98→      
 99→      // Step 1: Fetch scoped transactions
100→      const transactions = fetchScopedTransactions(db, employee.id, period, employee.territory_id);
101→      log(1, 'Fetch Transactions', { employee: employee.name, count: transactions.length });
102→      
103→      // Step 2: Apply mapping filters (include/exclude)
104→      const filtered = applyMappingFilters(db, transactions, ruleSets);
105→      log(2, 'Apply Mapping Filters', { employee: employee.name, before: transactions.length, after: filtered.length });
106→      
107→      // Eligibility check (runs after step 2, needs transaction data)
108→      const eligibility = checkEligibility(filtered, eligibilityRules, empContext);
109→      log(2.5, 'Eligibility Check', { employee: employee.name, status: eligibility.status, details: eligibility.details });
110→      
111→      const kpiResults = [];
112→      
113→      for (const planKpi of planKpis) {
114→        const targetValue = overrides.targets?.[planKpi.kpi_id] ?? planKpi.target_value;
115→        
116→        // Step 3: Calculate KPI achievement
117→        const achievement = calculateKpiAchievement(filtered, planKpi, employee, period, db);
118→        log(3, 'KPI Achievement', { employee: employee.name, kpi: planKpi.kpi_name, actual: achievement.actual, target: targetValue, percent: achievement.percent });
119→        
120→        // Step 4: Determine slab
121→        const slabSet = slabSets[planKpi.kpi_id];
122→        const slabResult = determineSlab(achievement.percent, slabSet, overrides.slabs?.[planKpi.kpi_id]);
123→        log(4, 'Determine Slab', { employee: employee.name, kpi: planKpi.kpi_name, slab_type: slabResult.type, rate: slabResult.rate });
124→        
125→        // Step 5: Calculate KPI payout
126→        const kpiPayout = calculateKpiPayout(achievement, slabResult, empContext);
127→        log(5, 'KPI Payout', { employee: employee.name, kpi: planKpi.kpi_name, raw_payout: kpiPayout.amount });
128→        
129→        // Step 6: Apply weight
130→        const weighted = applyWeight(kpiPayout.amount, planKpi.weight);
131→        log(6, 'Apply Weight', { employee: employee.name, kpi: planKpi.kpi_name, weight: planKpi.weight, weighted_payout: weighted });
132→        
133→        kpiResults.push({
134→          kpi_id: planKpi.kpi_id,
135→          kpi_name: planKpi.kpi_name,
136→          kpi_code: planKpi.kpi_code,
137→          kpi_category: planKpi.kpi_category,
138→          unit: planKpi.unit,
139→          target_value: targetValue,
140→          actual_value: achievement.actual,
141→          achievement_percent: achievement.percent,
142→          slab_rate: slabResult.rate,
143→          slab_type: slabResult.type,
144→          raw_payout: kpiPayout.amount,
145→          weighted_payout: weighted,
146→          weight: planKpi.weight,
147→          calculation_details: JSON.stringify({
148→            achievement,
149→            slab: slabResult,
150→            payout: kpiPayout,
151→          }),
152→        });
153→      }
154→      
155→      // Step 7: Aggregate KPIs
156→      const grossPayout = aggregateKpis(kpiResults);
157→      log(7, 'Aggregate KPIs', { employee: employee.name, gross_payout: grossPayout });
158→      
159→      // Step 8: Apply multiplier
160→      const multiplierResult = applyMultiplier(grossPayout, multiplierRules, filtered, employee, period, db, overrides.multipliers);
161→      log(8, 'Apply Multiplier', { employee: employee.name, multiplier_amount: multiplierResult.amount, applied: multiplierResult.applied });
162→      
163→      // Step 9: Apply penalty
164→      const penaltyResult = applyPenalty(grossPayout + multiplierResult.amount, penaltyRules, filtered);
165→      log(9, 'Apply Penalty', { employee: employee.name, penalty_amount: penaltyResult.amount, triggered: penaltyResult.triggered });
166→      
167→      let netPayout = grossPayout + multiplierResult.amount - penaltyResult.amount;
168→      
169→      // Apply eligibility reduction
170→      if (eligibility.status === 'ineligible') {
171→        netPayout = 0;
172→      } else if (eligibility.status === 'reduced') {
173→        netPayout = netPayout * (1 - eligibility.reduction / 100);
174→      }
175→      
176→      // Step 10: Apply cap
177→      const capResult = applyCap(netPayout, cappingRules, employee);
178→      log(10, 'Apply Cap', { employee: employee.name, before: netPayout, after: capResult.capped, cap_hit: capResult.applied });
179→      
180→      netPayout = capResult.capped;
181→      
182→      // Handle split (adjust net payout for split roles)
183→      let splitAdjustment = 0;
184→      if (splitRules.length > 0) {
185→        for (const sr of splitRules) {
186→          const participant = sr.participants.find(p => p.role_id === employee.role_id);
187→          if (participant) {
188→            splitAdjustment = netPayout - (netPayout * participant.split_percent / 100);
189→            netPayout = netPayout * participant.split_percent / 100;
190→          }
191→        }
192→      }
193→      
194→      const payoutRecord = {
195→        employee,
196→        run_id: runId,
197→        gross_payout: grossPayout,
198→        multiplier_amount: multiplierResult.amount,
199→        penalty_amount: penaltyResult.amount,
200→        cap_adjustment: capResult.adjustment,
201→        split_adjustment: splitAdjustment,
202→        net_payout: Math.round(netPayout * 100) / 100,
203→        eligibility_status: eligibility.status,
204→        eligibility_details: eligibility.details,
205→        kpi_results: kpiResults,
206→        calculation_details: {
207→          multiplier: multiplierResult,
208→          penalty: penaltyResult,
209→          cap: capResult,
210→          eligibility,
211→        },
212→      };
213→      
214→      // Step 11: Store payout
215→      const payoutId = storePayout(db, payoutRecord, plan_id, period);
216→      log(11, 'Store Payout', { employee: employee.name, payout_id: payoutId, net_payout: payoutRecord.net_payout });
217→      
218→      // Step 12: Create approval entry (only for real runs)
219→      if (!is_simulation) {
220→        createApproval(db, payoutId);
221→        log(12, 'Create Approval', { employee: employee.name, status: 'submitted' });
222→      }
223→      
224→      allPayouts.push({ ...payoutRecord, id: payoutId });
225→    }
226→    
227→    // Step 13: Complete the run
228→    const totalPayout = allPayouts.reduce((sum, p) => sum + p.net_payout, 0);
229→    db.prepare(`
230→      UPDATE calculation_runs SET status = 'completed', total_payout = ?, employee_count = ?,
231→        completed_at = datetime('now'), calculation_details = ?
232→      WHERE id = ?
233→    `).run(Math.round(totalPayout * 100) / 100, allPayouts.length, JSON.stringify({ steps }), runId);
234→    log(13, 'Complete', { total_payout: totalPayout, employee_count: allPayouts.length });
235→    
236→    return {
237→      run_id: runId,
238→      plan_id,
239→      period,
240→      status: 'completed',
241→      is_simulation,
242→      total_payout: Math.round(totalPayout * 100) / 100,
243→      employee_count: allPayouts.length,
244→      payouts: allPayouts.map(p => ({
245→        employee_id: p.employee.id,
246→        employee_name: p.employee.name,
247→        role_name: p.employee.role_name,
248→        gross_payout: p.gross_payout,
249→        net_payout: p.net_payout,
250→        eligibility_status: p.eligibility_status,
251→      })),
252→      steps,
253→    };
254→  } catch (err) {
255→    db.prepare("UPDATE calculation_runs SET status = 'failed', completed_at = datetime('now') WHERE id = ?").run(runId);
256→    throw err;
257→  }
258→}
