 11→const PIPELINE_STEPS = [
 12→  { step: 1, name: 'Fetch Transactions', desc: 'Loading scoped transaction data' },
 13→  { step: 2, name: 'Apply Filters', desc: 'Include/exclude mapping rules' },
 14→  { step: 2.5, name: 'Eligibility Check', desc: 'Verify minimum criteria' },
 15→  { step: 3, name: 'KPI Achievement', desc: 'Calculate actual vs target' },
 16→  { step: 4, name: 'Determine Slab', desc: 'Match achievement to slab tier' },
 17→  { step: 5, name: 'KPI Payout', desc: 'Calculate raw payout per KPI' },
 18→  { step: 6, name: 'Apply Weight', desc: 'Weight-adjusted payout' },
 19→  { step: 7, name: 'Aggregate KPIs', desc: 'Sum to gross payout' },
 20→  { step: 8, name: 'Apply Multiplier', desc: 'Growth/strategic bonuses' },
 21→  { step: 9, name: 'Apply Penalty', desc: 'Deductions for violations' },
 22→  { step: 10, name: 'Apply Cap', desc: 'Enforce payout limits' },
 23→  { step: 11, name: 'Store Payout', desc: 'Persist results to database' },
 24→  { step: 12, name: 'Create Approval', desc: 'Submit for approval workflow' },
 25→  { step: 13, name: 'Complete', desc: 'Finalize calculation run' },
