 28→export default function CalculationPage() {
 29→  const { selectedPeriod } = useAppStore();
 30→  const [plans, setPlans] = useState([]);
 31→  const [selectedPlan, setSelectedPlan] = useState('');
 32→  const [running, setRunning] = useState(false);
 33→  const [currentStep, setCurrentStep] = useState(-1);
 34→  const [result, setResult] = useState(null);
 35→  const [pastRuns, setPastRuns] = useState([]);
 36→  const [expandedPayout, setExpandedPayout] = useState(null);
 37→  const [payoutDetail, setPayoutDetail] = useState(null);
 38→  const [loading, setLoading] = useState(true);
 39→
 40→  useEffect(() => {
 41→    Promise.all([api.get('/plans'), api.get('/calculation/runs')])
 42→      .then(([p, r]) => {
 43→        setPlans(p.filter(pl => pl.status === 'active'));
 44→        setPastRuns(r);
 45→        if (p.length > 0) setSelectedPlan(p[0].id);
 46→      })
 47→      .finally(() => setLoading(false));
 48→  }, []);
 49→
 50→  const runCalculation = async () => {
 51→    if (!selectedPlan) return toast.error('Select a plan first');
 52→    setRunning(true);
 53→    setResult(null);
 54→    setCurrentStep(0);
 55→
 56→    // Animate steps
 57→    const stepAnimation = setInterval(() => {
 58→      setCurrentStep(prev => {
 59→        if (prev >= PIPELINE_STEPS.length - 1) {
 60→          clearInterval(stepAnimation);
 61→          return prev;
 62→        }
 63→        return prev + 1;
 64→      });
 65→    }, 300);
 66→
 67→    try {
 68→      const res = await api.post('/calculation/run', {
 69→        plan_id: selectedPlan,
 70→        period: selectedPeriod,
 71→        created_by: 'emp-01',
 72→      });
 73→      
 74→      clearInterval(stepAnimation);
 75→      setCurrentStep(PIPELINE_STEPS.length - 1);
 76→      setResult(res);
 77→      toast.success(`Calculation complete! ${res.employee_count} employees processed`);
 78→      
 79→      // Refresh past runs
 80→      const runs = await api.get('/calculation/runs');
 81→      setPastRuns(runs);
 82→    } catch (err) {
 83→      clearInterval(stepAnimation);
 84→      toast.error(err.message);
 85→    } finally {
 86→      setRunning(false);
 87→    }
 88→  };
 89→
 90→  const loadPayoutDetail = async (payoutId) => {
 91→    if (expandedPayout === payoutId) {
