112→    }
113→  };
114→
115→  if (loading) {
116→    return <div className="h-96 bg-slate-100 rounded-xl animate-pulse" />;
117→  }
118→
119→  return (
120→    <div className="space-y-6">
121→      <div>
122→        <h1 className="text-2xl font-bold text-slate-900">Calculate Commission</h1>
