124→      </div>
125→
126→      {/* Controls */}
127→      <div className="card p-5">
128→        <div className="flex items-end gap-4">
129→          <div className="flex-1 max-w-xs">
130→            <label className="label">Commission Plan</label>
131→            <select className="input" value={selectedPlan} onChange={e => setSelectedPlan(e.target.value)}>
