133→            </select>
134→          </div>
135→          <div>
136→            <label className="label">Period</label>
137→            <div className="input bg-slate-50 text-slate-600">{selectedPeriod}</div>
138→          </div>
139→          <button
140→            onClick={runCalculation}
141→            disabled={running || !selectedPlan}
142→            className="btn-primary flex items-center gap-2 h-[42px]"
143→          >
144→            {running ? <Loader2 className="w-4 h-4 animate-spin" /> : <Play className="w-4 h-4" />}
145→            {running ? 'Running...' : 'Run Calculation'}
146→          </button>
147→        </div>
148→      </div>
149→
150→      {/* Pipeline Visualizer */}
151→      {currentStep >= 0 && (
152→        <div className="card p-5">
153→          <h3 className="font-semibold text-slate-900 mb-4">Pipeline Progress</h3>
154→          <div className="grid grid-cols-7 gap-1">
155→            {PIPELINE_STEPS.map((step, i) => {
