160→                  <div className={cn(
161→                    'w-8 h-8 rounded-full mx-auto flex items-center justify-center text-xs font-bold transition-all duration-300',
162→                    isComplete ? 'bg-emerald-500 text-white scale-100' :
163→                    isCurrent ? 'bg-primary-500 text-white animate-pulse scale-110' :
164→                    'bg-slate-200 text-slate-400'
