  1→import { Router } from 'express';
  2→import { getDb } from '../db/database.js';
  3→import { v4 as uuid } from 'uuid';
  4→
  5→const router = Router();
  6→
  7→// List all plans
  8→router.get('/', (req, res) => {
  9→  const db = getDb();
 10→  const plans = db.prepare('SELECT * FROM commission_plans ORDER BY created_at DESC').all();
 11→  
 12→  // Enrich with roles and territory counts
 13→  const enriched = plans.map(plan => {
 14→    const roles = db.prepare(`
 15→      SELECT r.id, r.name FROM plan_roles pr
 16→      JOIN roles r ON pr.role_id = r.id
 17→      WHERE pr.plan_id = ?
 18→    `).all(plan.id);
 19→    
 20→    const kpiCount = db.prepare('SELECT COUNT(*) as count FROM plan_kpis WHERE plan_id = ?').get(plan.id).count;
 21→    const territoryCount = db.prepare('SELECT COUNT(*) as count FROM plan_territories WHERE plan_id = ?').get(plan.id).count;
 22→    
 23→    return { ...plan, roles, kpi_count: kpiCount, territory_count: territoryCount };
 24→  });
 25→  
 26→  res.json(enriched);
 27→});
 28→
 29→// Get single plan with all config
 30→router.get('/:id', (req, res) => {
 31→  const db = getDb();
 32→  const plan = db.prepare('SELECT * FROM commission_plans WHERE id = ?').get(req.params.id);
 33→  if (!plan) return res.status(404).json({ error: 'Plan not found' });
 34→  
 35→  // Roles
 36→  plan.roles = db.prepare(`
 37→    SELECT r.* FROM plan_roles pr JOIN roles r ON pr.role_id = r.id WHERE pr.plan_id = ?
 38→  `).all(plan.id);
 39→  
 40→  // Territories
 41→  plan.territories = db.prepare(`
 42→    SELECT t.* FROM plan_territories pt JOIN territories t ON pt.territory_id = t.id WHERE pt.plan_id = ?
 43→  `).all(plan.id);
 44→  
 45→  // KPIs with slab config
 46→  plan.kpis = db.prepare(`
 47→    SELECT pk.*, k.name as kpi_name, k.code as kpi_code, k.category as kpi_category,
 48→           k.formula, k.unit, k.direction
 49→    FROM plan_kpis pk
 50→    JOIN kpi_definitions k ON pk.kpi_id = k.id
 51→    WHERE pk.plan_id = ?
 52→  `).all(plan.id);
 53→  
 54→  // Slab sets and tiers
 55→  plan.slab_sets = db.prepare('SELECT * FROM slab_sets WHERE plan_id = ?').all(plan.id);
 56→  for (const ss of plan.slab_sets) {
 57→    ss.tiers = db.prepare('SELECT * FROM slab_tiers WHERE slab_set_id = ? ORDER BY tier_order').all(ss.id);
 58→  }
 59→  
 60→  // Rules
 61→  plan.rule_sets = db.prepare('SELECT * FROM rule_sets WHERE plan_id = ?').all(plan.id);
 62→  for (const rs of plan.rule_sets) {
 63→    rs.rules = db.prepare('SELECT * FROM rules WHERE rule_set_id = ?').all(rs.id);
 64→  }
 65→  
 66→  // Eligibility
 67→  plan.eligibility_rules = db.prepare('SELECT * FROM eligibility_rules WHERE plan_id = ?').all(plan.id);
 68→  
 69→  // Multipliers
 70→  plan.multiplier_rules = db.prepare('SELECT * FROM multiplier_rules WHERE plan_id = ?').all(plan.id);
 71→  
 72→  // Penalties
 73→  plan.penalty_rules = db.prepare('SELECT * FROM penalty_rules WHERE plan_id = ?').all(plan.id);
 74→  
 75→  // Caps
 76→  plan.capping_rules = db.prepare('SELECT * FROM capping_rules WHERE plan_id = ?').all(plan.id);
 77→  
 78→  // Splits
 79→  plan.split_rules = db.prepare('SELECT * FROM split_rules WHERE plan_id = ?').all(plan.id);
 80→  for (const sr of plan.split_rules) {
 81→    sr.participants = db.prepare(`
 82→      SELECT sp.*, r.name as role_name
 83→      FROM split_participants sp
 84→      JOIN roles r ON sp.role_id = r.id
 85→      WHERE sp.split_rule_id = ?
 86→    `).all(sr.id);
 87→  }
 88→  
 89→  res.json(plan);
 90→});
