130→  `).run(name, description, status, plan_type, effective_from, effective_to, base_payout, req.params.id);
131→  
132→  // Audit
133→  db.prepare(`INSERT INTO audit_trail (id, entity_type, entity_id, action, changes, performed_by)
134→    VALUES (?, 'plan', ?, 'updated', ?, ?)`).run(uuid(), req.params.id, JSON.stringify(req.body), req.body.updated_by);
