import { useState, useEffect } from 'react';
import api from '../api/client';
import { useAppStore } from '../store/store';
import toast from 'react-hot-toast';
import {
  Calculator, Play, CheckCircle2, XCircle, Clock, ChevronDown, ChevronRight,
  Loader2, ArrowRight, TrendingUp, AlertTriangle, Shield, Sparkles, Download
} from 'lucide-react';
import { formatCurrency, formatPercent, cn, getStatusColor, getStatusLabel } from '../lib/utils';

const PIPELINE_STEPS = [
  { step: 1, name: 'Fetch Transactions', desc: 'Loading scoped transaction data' },
  { step: 2, name: 'Apply Filters', desc: 'Include/exclude mapping rules' },
  { step: 2.5, name: 'Eligibility Check', desc: 'Verify minimum criteria' },
  { step: 3, name: 'KPI Achievement', desc: 'Calculate actual vs target' },
  { step: 4, name: 'Determine Slab', desc: 'Match achievement to slab tier' },
  { step: 5, name: 'KPI Payout', desc: 'Calculate raw payout per KPI' },
  { step: 6, name: 'Apply Weight', desc: 'Weight-adjusted payout' },
  { step: 7, name: 'Aggregate KPIs', desc: 'Sum to gross payout' },
  { step: 8, name: 'Apply Multiplier', desc: 'Growth/strategic bonuses' },
  { step: 9, name: 'Apply Penalty', desc: 'Deductions for violations' },
  { step: 10, name: 'Apply Cap', desc: 'Enforce payout limits' },
  { step: 11, name: 'Store Payout', desc: 'Persist results to database' },
  { step: 12, name: 'Create Approval', desc: 'Submit for approval workflow' },
  { step: 13, name: 'Complete', desc: 'Finalize calculation run' },
];

export default function CalculationPage() {
  const { selectedPeriod } = useAppStore();
  const [plans, setPlans] = useState([]);
  const [selectedPlan, setSelectedPlan] = useState('');
  const [running, setRunning] = useState(false);
  const [currentStep, setCurrentStep] = useState(-1);
  const [result, setResult] = useState(null);
  const [pastRuns, setPastRuns] = useState([]);
  const [expandedPayout, setExpandedPayout] = useState(null);
  const [payoutDetail, setPayoutDetail] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([api.get('/plans'), api.get('/calculation/runs')])
      .then(([p, r]) => {
        setPlans(p.filter(pl => pl.status === 'active'));
        setPastRuns(r);
        if (p.length > 0) setSelectedPlan(p[0].id);
      })
      .finally(() => setLoading(false));
  }, []);

  const runCalculation = async () => {
    if (!selectedPlan) return toast.error('Select a plan first');
    setRunning(true);
    setResult(null);
    setCurrentStep(0);

    // Animate steps
    const stepAnimation = setInterval(() => {
      setCurrentStep(prev => {
        if (prev >= PIPELINE_STEPS.length - 1) {
          clearInterval(stepAnimation);
          return prev;
        }
        return prev + 1;
      });
    }, 300);

    try {
      const res = await api.post('/calculation/run', {
        plan_id: selectedPlan,
        period: selectedPeriod,
        created_by: 'emp-01',
      });

      clearInterval(stepAnimation);
      setCurrentStep(PIPELINE_STEPS.length - 1);
      setResult(res);
      toast.success(`Calculation complete! ${res.employee_count} employees processed`);

      // Refresh past runs
      const runs = await api.get('/calculation/runs');
      setPastRuns(runs);
    } catch (err) {
      clearInterval(stepAnimation);
      toast.error(err.message);
    } finally {
      setRunning(false);
    }
  };

  const loadPayoutDetail = async (payoutId) => {
    if (expandedPayout === payoutId) {
      setExpandedPayout(null);
      setPayoutDetail(null);
      return;
    }
    try {
      const detail = await api.get(`/calculation/payouts/${payoutId}`);
      setPayoutDetail(detail);
      setExpandedPayout(payoutId);
    } catch (err) {
      toast.error('Failed to load payout details');
    }
  };

  const loadRunDetail = async (runId) => {
    try {
      const run = await api.get(`/calculation/runs/${runId}`);
      setResult(run);
      setCurrentStep(PIPELINE_STEPS.length - 1);
    } catch (err) {
      toast.error('Failed to load run details');
    }
  };

  if (loading) {
    return <div className="h-96 bg-slate-100 rounded-xl animate-pulse" />;
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-900">Calculate Commission</h1>
        <p className="text-slate-500 mt-1">Run the 13-step calculation pipeline</p>
      </div>

      {/* Controls */}
      <div className="card p-5">
        <div className="flex items-end gap-4">
          <div className="flex-1 max-w-xs">
            <label className="label">Commission Plan</label>
            <select className="input" value={selectedPlan} onChange={e => setSelectedPlan(e.target.value)}>
              {plans.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>
          <div>
            <label className="label">Period</label>
            <div className="input bg-slate-50 text-slate-600">{selectedPeriod}</div>
          </div>
          <button
            onClick={runCalculation}
            disabled={running || !selectedPlan}
            className="btn-primary flex items-center gap-2 h-[42px]"
          >
            {running ? <Loader2 className="w-4 h-4 animate-spin" /> : <Play className="w-4 h-4" />}
            {running ? 'Running...' : 'Run Calculation'}
          </button>
        </div>
      </div>

      {/* Pipeline Visualizer */}
      {currentStep >= 0 && (
        <div className="card p-5">
          <h3 className="font-semibold text-slate-900 mb-4">Pipeline Progress</h3>
          <div className="grid grid-cols-7 gap-1">
            {PIPELINE_STEPS.map((step, i) => {
              const isComplete = i <= currentStep;
              const isCurrent = i === currentStep && running;
              return (
                <div key={step.step} className="text-center">
                  <div className={cn(
                    'w-8 h-8 rounded-full mx-auto flex items-center justify-center text-xs font-bold transition-all duration-300',
                    isComplete ? 'bg-emerald-500 text-white scale-100' :
                    isCurrent ? 'bg-primary-500 text-white animate-pulse scale-110' :
                    'bg-slate-200 text-slate-400'
                  )}>
                    {isComplete && !isCurrent ? <CheckCircle2 className="w-4 h-4" /> : 
                     isCurrent ? <Loader2 className="w-4 h-4 animate-spin" /> : 
                     Math.floor(step.step)}
                  </div>
                  <div className={cn(
                    'text-[10px] mt-1 leading-tight',
                    isComplete ? 'text-slate-700 font-medium' : 'text-slate-400'
                  )}>
                    {step.name}
                  </div>
                </div>
              );
            })}
          </div>
          {/* Progress bar */}
          <div className="mt-4 h-2 bg-slate-200 rounded-full overflow-hidden">
            <div
              className="h-full bg-gradient-to-r from-primary-500 to-emerald-500 rounded-full transition-all duration-300"
              style={{ width: `${((currentStep + 1) / PIPELINE_STEPS.length) * 100}%` }}
            />
          </div>
        </div>
      )}

      {/* Results */}
      {result && result.payouts && (
        <div className="card">
          <div className="p-5 border-b border-slate-200">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="font-semibold text-slate-900">Calculation Results</h3>
                <p className="text-sm text-slate-500">{result.employee_count} employees • Run ID: {result.run_id?.slice(0, 8)}</p>
              </div>
              <div className="text-right">
                <div className="text-2xl font-bold text-slate-900">{formatCurrency(result.total_payout)}</div>
                <div className="text-sm text-slate-500">Total Payout</div>
              </div>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-slate-200 bg-slate-50">
                  <th className="text-left py-3 px-5 font-medium text-slate-600">Employee</th>
                  <th className="text-left py-3 px-4 font-medium text-slate-600">Role</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Gross</th>
                  <th className="text-right py-3 px-4 font-medium text-slate-600">Net Payout</th>
                  <th className="text-center py-3 px-4 font-medium text-slate-600">Eligibility</th>
                  <th className="text-center py-3 px-4 font-medium text-slate-600">Details</th>
                </tr>
              </thead>
              <tbody>
                {result.payouts.map(p => (
                  <tr key={p.employee_id} className="border-b border-slate-100 hover:bg-slate-50 cursor-pointer" onClick={() => {
                    const match = result.payouts_full || [];
                    // Try to load detail from API
                    if (result.run_id) {
                      api.get(`/calculation/runs/${result.run_id}`).then(run => {
                        const payout = run.payouts?.find(ep => ep.employee_id === p.employee_id);
                        if (payout) loadPayoutDetail(payout.id);
                      });
                    }
                  }}>
                    <td className="py-3 px-5">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-primary-100 text-primary-700 flex items-center justify-center text-xs font-semibold">
                          {p.employee_name.split(' ').map(n => n[0]).join('')}
                        </div>
                        <span className="font-medium text-slate-900">{p.employee_name}</span>
                      </div>
                    </td>
                    <td className="py-3 px-4 text-slate-600">{p.role_name}</td>
                    <td className="py-3 px-4 text-right text-slate-600">{formatCurrency(p.gross_payout)}</td>
                    <td className="py-3 px-4 text-right font-semibold text-slate-900">{formatCurrency(p.net_payout)}</td>
                    <td className="py-3 px-4 text-center">
                      <span className={cn('badge', {
                        'badge-success': p.eligibility_status === 'eligible',
                        'badge-warning': p.eligibility_status === 'reduced',
                        'badge-danger': p.eligibility_status === 'ineligible',
                      })}>
                        {p.eligibility_status}
                      </span>
                    </td>
                    <td className="py-3 px-4 text-center">
                      <ChevronRight className="w-4 h-4 text-slate-400 mx-auto" />
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Coming Soon */}
      {!running && !result && pastRuns.length === 0 && (
        <div className="card p-8 text-center">
          <Calculator className="w-12 h-12 text-slate-300 mx-auto mb-3" />
          <h3 className="text-lg font-medium text-slate-700 mb-1">Ready to Calculate</h3>
          <p className="text-slate-500 mb-4">Select a plan and period above, then click Run Calculation</p>
          <div className="flex items-center justify-center gap-2 text-sm text-slate-400">
            <Sparkles className="w-4 h-4 text-violet-400" />
            <span>Coming soon: Export to Excel, bulk period calculations, scheduled runs</span>
          </div>
        </div>
      )}

      {/* Past Runs */}
      {pastRuns.length > 0 && (
        <div className="card">
          <div className="p-5 border-b border-slate-200">
            <h3 className="font-semibold text-slate-900">Past Calculation Runs</h3>
          </div>
          <div className="divide-y divide-slate-100">
            {pastRuns.slice(0, 10).map(run => (
              <button
                key={run.id}
                onClick={() => loadRunDetail(run.id)}
                className="w-full flex items-center justify-between px-5 py-3 hover:bg-slate-50 text-left"
              >
                <div className="flex items-center gap-4">
                  <span className={cn('badge', getStatusColor(run.status))}>{getStatusLabel(run.status)}</span>
                  <div>
                    <div className="text-sm font-medium text-slate-900">{run.plan_name}</div>
                    <div className="text-xs text-slate-500">Period: {run.period} • {run.employee_count} employees</div>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-sm font-semibold text-slate-900">{formatCurrency(run.total_payout)}</div>
                  <div className="text-xs text-slate-500">{run.started_at}</div>
                </div>
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api/client';
import toast from 'react-hot-toast';
import { cn, formatCurrency, getStatusColor, getStatusLabel } from '../lib/utils';
import {
  ArrowLeft, Settings, Target, BarChart3, Filter, ShieldCheck,
  Zap, AlertTriangle, ArrowUpDown, Scissors, Save, ChevronDown,
  Sparkles, AlertCircle
} from 'lucide-react';

const tabs = [
  { id: 'general', label: 'General', icon: Settings },
  { id: 'kpis', label: 'KPIs & Weights', icon: Target },
  { id: 'slabs', label: 'Slabs', icon: BarChart3 },
  { id: 'rules', label: 'Include/Exclude', icon: Filter },
  { id: 'eligibility', label: 'Eligibility', icon: ShieldCheck },
  { id: 'multipliers', label: 'Multipliers', icon: Zap },
  { id: 'penalties', label: 'Penalties', icon: AlertTriangle },
  { id: 'caps', label: 'Caps & Splits', icon: Scissors },
];

export default function PlanBuilderPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [plan, setPlan] = useState(null);
  const [activeTab, setActiveTab] = useState('general');
  const [loading, setLoading] = useState(!!id);
  const [allRoles, setAllRoles] = useState([]);
  const [allTerritories, setAllTerritories] = useState([]);
  const [allKpis, setAllKpis] = useState([]);

  useEffect(() => {
    const loads = [
      api.get('/roles'),
      api.get('/territories'),
      api.get('/kpis'),
    ];
    if (id && id !== 'new') loads.push(api.get(`/plans/${id}`));

    Promise.all(loads).then(([roles, territories, kpis, planData]) => {
      setAllRoles(roles);
      setAllTerritories(territories);
      setAllKpis(kpis);
      if (planData) setPlan(planData);
      else setPlan({
        name: '', description: '', status: 'draft', plan_type: 'monthly',
        effective_from: '2026-01-01', effective_to: '2026-12-31', base_payout: 15000,
        roles: [], territories: [], kpis: [], slab_sets: [], rule_sets: [],
        eligibility_rules: [], multiplier_rules: [], penalty_rules: [],
        capping_rules: [], split_rules: [],
      });
    }).catch(err => {
      toast.error('Failed to load plan data');
    }).finally(() => setLoading(false));
  }, [id]);

  if (loading || !plan) {
    return (
      <div className="space-y-6">
        <div className="h-8 w-64 bg-slate-200 rounded animate-pulse" />
        <div className="card p-8">
          <div className="h-96 bg-slate-100 rounded animate-pulse" />
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4">
        <button onClick={() => navigate('/plans')} className="p-2 hover:bg-slate-100 rounded-lg transition-colors">
          <ArrowLeft className="w-5 h-5 text-slate-600" />
        </button>
        <div className="flex-1">
          <h1 className="text-2xl font-bold text-slate-900">
            {plan.id ? plan.name : 'New Commission Plan'}
          </h1>
          {plan.id && (
            <div className="flex items-center gap-3 mt-1">
              <span className={cn('badge', getStatusColor(plan.status))}>{getStatusLabel(plan.status)}</span>
              <span className="text-sm text-slate-500">{plan.plan_type}</span>
            </div>
          )}
        </div>
      </div>

      {/* Tab Navigation */}
      <div className="border-b border-slate-200">
        <div className="flex gap-1 overflow-x-auto pb-px">
          {tabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={cn(
                'flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap',
                activeTab === tab.id
                  ? 'border-primary-600 text-primary-600'
                  : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
              )}
            >
              <tab.icon className="w-4 h-4" />
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Tab Content */}
      <div className="card p-6">
        {activeTab === 'general' && <GeneralTab plan={plan} setPlan={setPlan} allRoles={allRoles} allTerritories={allTerritories} />}
        {activeTab === 'kpis' && <KpisTab plan={plan} setPlan={setPlan} allKpis={allKpis} />}
        {activeTab === 'slabs' && <SlabsTab plan={plan} />}
        {activeTab === 'rules' && <RulesTab plan={plan} />}
        {activeTab === 'eligibility' && <EligibilityTab plan={plan} />}
        {activeTab === 'multipliers' && <MultipliersTab plan={plan} />}
        {activeTab === 'penalties' && <PenaltiesTab plan={plan} />}
        {activeTab === 'caps' && <CapsTab plan={plan} />}
      </div>
    </div>
  );
}

// ====== TAB COMPONENTS ======

function GeneralTab({ plan, setPlan, allRoles, allTerritories }) {
  return (
    <div className="space-y-6 max-w-2xl">
      <div>
        <label className="label">Plan Name</label>
        <input className="input" value={plan.name} onChange={e => setPlan({...plan, name: e.target.value})} placeholder="e.g., Field Sales Monthly Incentive" />
      </div>
      <div>
        <label className="label">Description</label>
        <textarea className="input min-h-[80px]" value={plan.description || ''} onChange={e => setPlan({...plan, description: e.target.value})} placeholder="Describe the plan purpose..." />
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="label">Plan Type</label>
          <select className="input" value={plan.plan_type} onChange={e => setPlan({...plan, plan_type: e.target.value})}>
            <option value="monthly">Monthly</option>
            <option value="quarterly">Quarterly</option>
            <option value="annual">Annual</option>
          </select>
        </div>
        <div>
          <label className="label">Base Payout</label>
          <input type="number" className="input" value={plan.base_payout} onChange={e => setPlan({...plan, base_payout: Number(e.target.value)})} />
        </div>
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="label">Effective From</label>
          <input type="date" className="input" value={plan.effective_from} onChange={e => setPlan({...plan, effective_from: e.target.value})} />
        </div>
        <div>
          <label className="label">Effective To</label>
          <input type="date" className="input" value={plan.effective_to} onChange={e => setPlan({...plan, effective_to: e.target.value})} />
        </div>
      </div>
      <div>
        <label className="label">Status</label>
        <select className="input max-w-xs" value={plan.status} onChange={e => setPlan({...plan, status: e.target.value})}>
          <option value="draft">Draft</option>
          <option value="active">Active</option>
          <option value="expired">Expired</option>
          <option value="archived">Archived</option>
        </select>
      </div>

      {/* Applicable Roles */}
      <div>
        <label className="label">Applicable Roles</label>
        <div className="flex flex-wrap gap-2 mt-2">
          {allRoles.map(role => {
            const selected = plan.roles?.some(r => r.id === role.id);
            return (
              <button
                key={role.id}
                className={cn(
                  'px-3 py-1.5 rounded-lg text-sm font-medium border transition-colors',
                  selected ? 'bg-primary-50 border-primary-300 text-primary-700' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                )}
                onClick={() => {
                  const newRoles = selected
                    ? plan.roles.filter(r => r.id !== role.id)
                    : [...(plan.roles || []), role];
                  setPlan({...plan, roles: newRoles});
                }}
              >
                {role.name}
              </button>
            );
          })}
        </div>
      </div>

      {/* Territories */}
      <div>
        <label className="label">Territories</label>
        <div className="flex flex-wrap gap-2 mt-2">
          {allTerritories.map(terr => {
            const selected = plan.territories?.some(t => t.id === terr.id);
            return (
              <button
                key={terr.id}
                className={cn(
                  'px-3 py-1.5 rounded-lg text-sm font-medium border transition-colors',
                  selected ? 'bg-emerald-50 border-emerald-300 text-emerald-700' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                )}
                onClick={() => {
                  const newTerrs = selected
                    ? plan.territories.filter(t => t.id !== terr.id)
                    : [...(plan.territories || []), terr];
                  setPlan({...plan, territories: newTerrs});
                }}
              >
                {terr.name}
                <span className="ml-1 text-xs opacity-60">({terr.type})</span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}

