import { Router } from 'express';
import { getDb } from '../db/database.js';
import { v4 as uuid } from 'uuid';

const router = Router();

// List all plans
router.get('/', (req, res) => {
  const db = getDb();
  const plans = db.prepare('SELECT * FROM commission_plans ORDER BY created_at DESC').all();

  // Enrich with roles and territory counts
  const enriched = plans.map(plan => {
    const roles = db.prepare(`
      SELECT r.id, r.name FROM plan_roles pr
      JOIN roles r ON pr.role_id = r.id
      WHERE pr.plan_id = ?
    `).all(plan.id);

    const kpiCount = db.prepare('SELECT COUNT(*) as count FROM plan_kpis WHERE plan_id = ?').get(plan.id).count;
    const territoryCount = db.prepare('SELECT COUNT(*) as count FROM plan_territories WHERE plan_id = ?').get(plan.id).count;

    return { ...plan, roles, kpi_count: kpiCount, territory_count: territoryCount };
  });

  res.json(enriched);
});

// Get single plan with all config
router.get('/:id', (req, res) => {
  const db = getDb();
  const plan = db.prepare('SELECT * FROM commission_plans WHERE id = ?').get(req.params.id);
  if (!plan) return res.status(404).json({ error: 'Plan not found' });

  // Roles
  plan.roles = db.prepare(`
    SELECT r.* FROM plan_roles pr JOIN roles r ON pr.role_id = r.id WHERE pr.plan_id = ?
  `).all(plan.id);

  // Territories
  plan.territories = db.prepare(`
    SELECT t.* FROM plan_territories pt JOIN territories t ON pt.territory_id = t.id WHERE pt.plan_id = ?
  `).all(plan.id);

  // KPIs with slab config
  plan.kpis = db.prepare(`
    SELECT pk.*, k.name as kpi_name, k.code as kpi_code, k.category as kpi_category,
           k.formula, k.unit, k.direction
    FROM plan_kpis pk
    JOIN kpi_definitions k ON pk.kpi_id = k.id
    WHERE pk.plan_id = ?
  `).all(plan.id);

  // Slab sets and tiers
  plan.slab_sets = db.prepare('SELECT * FROM slab_sets WHERE plan_id = ?').all(plan.id);
  for (const ss of plan.slab_sets) {
    ss.tiers = db.prepare('SELECT * FROM slab_tiers WHERE slab_set_id = ? ORDER BY tier_order').all(ss.id);
  }

  // Rules
  plan.rule_sets = db.prepare('SELECT * FROM rule_sets WHERE plan_id = ?').all(plan.id);
  for (const rs of plan.rule_sets) {
    rs.rules = db.prepare('SELECT * FROM rules WHERE rule_set_id = ?').all(rs.id);
  }

  // Eligibility
  plan.eligibility_rules = db.prepare('SELECT * FROM eligibility_rules WHERE plan_id = ?').all(plan.id);

  // Multipliers
  plan.multiplier_rules = db.prepare('SELECT * FROM multiplier_rules WHERE plan_id = ?').all(plan.id);

  // Penalties
  plan.penalty_rules = db.prepare('SELECT * FROM penalty_rules WHERE plan_id = ?').all(plan.id);

  // Caps
  plan.capping_rules = db.prepare('SELECT * FROM capping_rules WHERE plan_id = ?').all(plan.id);

  // Splits
  plan.split_rules = db.prepare('SELECT * FROM split_rules WHERE plan_id = ?').all(plan.id);
  for (const sr of plan.split_rules) {
    sr.participants = db.prepare(`
      SELECT sp.*, r.name as role_name
      FROM split_participants sp
      JOIN roles r ON sp.role_id = r.id
      WHERE sp.split_rule_id = ?
    `).all(sr.id);
  }

  res.json(plan);
});

// Create plan
router.post('/', (req, res) => {
  const db = getDb();
  const id = uuid();
  const { name, description, plan_type, effective_from, effective_to, base_payout, created_by } = req.body;

  db.prepare(`
    INSERT INTO commission_plans (id, name, description, plan_type, effective_from, effective_to, base_payout, created_by)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).run(id, name, description, plan_type || 'monthly', effective_from, effective_to, base_payout || 0, created_by);

  // Add audit trail
  db.prepare(`INSERT INTO audit_trail (id, entity_type, entity_id, action, changes, performed_by)
    VALUES (?, 'plan', ?, 'created', ?, ?)`).run(uuid(), id, JSON.stringify({ name }), created_by);

  const plan = db.prepare('SELECT * FROM commission_plans WHERE id = ?').get(id);
  res.status(201).json(plan);
});

// Update plan
router.put('/:id', (req, res) => {
  const db = getDb();
  const plan = db.prepare('SELECT * FROM commission_plans WHERE id = ?').get(req.params.id);
  if (!plan) return res.status(404).json({ error: 'Plan not found' });

  const { name, description, status, plan_type, effective_from, effective_to, base_payout } = req.body;

  db.prepare(`
    UPDATE commission_plans SET
      name = COALESCE(?, name),
      description = COALESCE(?, description),
      status = COALESCE(?, status),
      plan_type = COALESCE(?, plan_type),
      effective_from = COALESCE(?, effective_from),
      effective_to = COALESCE(?, effective_to),
      base_payout = COALESCE(?, base_payout),
      updated_at = datetime('now')
    WHERE id = ?
  `).run(name, description, status, plan_type, effective_from, effective_to, base_payout, req.params.id);

  // Audit
  db.prepare(`INSERT INTO audit_trail (id, entity_type, entity_id, action, changes, performed_by)
    VALUES (?, 'plan', ?, 'updated', ?, ?)`).run(uuid(), req.params.id, JSON.stringify(req.body), req.body.updated_by);

  const updated = db.prepare('SELECT * FROM commission_plans WHERE id = ?').get(req.params.id);
  res.json(updated);
});

// Update plan roles
router.put('/:id/roles', (req, res) => {
  const db = getDb();
  const { role_ids } = req.body;

  db.prepare('DELETE FROM plan_roles WHERE plan_id = ?').run(req.params.id);
  const stmt = db.prepare('INSERT INTO plan_roles (id, plan_id, role_id) VALUES (?, ?, ?)');
  for (const roleId of role_ids) {
    stmt.run(uuid(), req.params.id, roleId);
  }

  res.json({ success: true });
});

// Update plan territories
router.put('/:id/territories', (req, res) => {
  const db = getDb();
  const { territory_ids } = req.body;

  db.prepare('DELETE FROM plan_territories WHERE plan_id = ?').run(req.params.id);
  const stmt = db.prepare('INSERT INTO plan_territories (id, plan_id, territory_id) VALUES (?, ?, ?)');
  for (const tid of territory_ids) {
    stmt.run(uuid(), req.params.id, tid);
  }

  res.json({ success: true });
});

// Update plan KPIs
router.put('/:id/kpis', (req, res) => {
  const db = getDb();
  const { kpis } = req.body; // Array of { kpi_id, weight, target_value, slab_set_id }

  db.prepare('DELETE FROM plan_kpis WHERE plan_id = ?').run(req.params.id);
  const stmt = db.prepare('INSERT INTO plan_kpis (id, plan_id, kpi_id, weight, target_value, slab_set_id) VALUES (?, ?, ?, ?, ?, ?)');
  for (const kpi of kpis) {
    stmt.run(uuid(), req.params.id, kpi.kpi_id, kpi.weight, kpi.target_value, kpi.slab_set_id || null);
  }

  res.json({ success: true });
});

export default router;

