247→        role_name: p.employee.role_name,
248→        gross_payout: p.gross_payout,
249→        net_payout: p.net_payout,
250→        eligibility_status: p.eligibility_status,
251→      })),
252→      steps,
253→    };
254→  } catch (err) {
